#define THREADS_PER_DIM 16
#define BLOCKS_PER_DIM 16
#define THREADS_PER_BLOCK (THREADS_PER_DIM*THREADS_PER_DIM)

#define ASSUMED_NR_CLUSTERS 32
#define FLT_MAX 3.40282347e+38

static float *feature_d;
static float *feature_flipped_d;
static int *membership_d;
static float *clusters_d;
static float *block_clusters_d;
static int *block_deltas_d;
static int *membership_new;
static float *block_new_centers;

static unsigned int num_threads_perdim = THREADS_PER_DIM;
static unsigned int num_blocks_perdim = BLOCKS_PER_DIM;
static unsigned int num_threads = THREADS_PER_BLOCK;
static unsigned int num_blocks;

static float *c_clusters_host;
static int nclusters_global;
static int nfeatures_global;
static int npoints_global;

static float euclid_dist_2_impl(float *pt1, float *pt2, int numdims) {
    int i;
    float ans = 0.0;
    for (i = 0; i < numdims; i++) {
        ans += (pt1[i] - pt2[i]) * (pt1[i] - pt2[i]);
    }
    return ans;
}

static int find_nearest_point_impl(float *pt, int nfeatures, float **pts, int npts) {
    int index = 0;
    int i;
    float max_dist = FLT_MAX;
    for (i = 0; i < npts; i++) {
        float dist = euclid_dist_2_impl(pt, pts[i], nfeatures);
        if (dist < max_dist) {
            max_dist = dist;
            index = i;
        }
    }
    return index;
}

float **kmeans_clustering(float **features, int nfeatures, int npoints, int nclusters, float threshold, int *membership) {
    int i, j, k;
    float **cluster_centres;
    int *new_centers_len;
    float **new_centers;
    int delta;
    int loop_count = 0;

    cluster_centres = (float **)malloc(nclusters * sizeof(float *));
    cluster_centres[0] = (float *)malloc(nclusters * nfeatures * sizeof(float));
    for (i = 1; i < nclusters; i++) {
        cluster_centres[i] = cluster_centres[0] + i * nfeatures;
    }

    new_centers_len = (int *)calloc(nclusters, sizeof(int));
    new_centers = (float **)malloc(nclusters * sizeof(float *));
    new_centers[0] = (float *)calloc(nclusters * nfeatures, sizeof(float));
    for (i = 1; i < nclusters; i++) {
        new_centers[i] = new_centers[0] + i * nfeatures;
    }

    for (i = 0; i < nclusters; i++) {
        for (j = 0; j < nfeatures; j++) {
            cluster_centres[i][j] = 0.0;
        }
    }

    for (i = 0; i < npoints; i++) {
        membership[i] = find_nearest_point_impl(features[i], nfeatures, cluster_centres, nclusters);
    }

    do {
        for (i = 0; i < nclusters; i++) {
            new_centers_len[i] = 0;
            for (j = 0; j < nfeatures; j++) {
                new_centers[i][j] = 0.0;
            }
        }

        for (i = 0; i < npoints; i++) {
            int cluster_id = membership[i];
            new_centers_len[cluster_id]++;
            for (j = 0; j < nfeatures; j++) {
                new_centers[cluster_id][j] += features[i][j];
            }
        }

        for (i = 0; i < nclusters; i++) {
            if (new_centers_len[i] > 0) {
                for (j = 0; j < nfeatures; j++) {
                    cluster_centres[i][j] = new_centers[i][j] / new_centers_len[i];
                }
            }
        }

        delta = 0;
        for (i = 0; i < npoints; i++) {
            int new_cluster = find_nearest_point_impl(features[i], nfeatures, cluster_centres, nclusters);
            if (new_cluster != membership[i]) {
                delta++;
                membership[i] = new_cluster;
            }
        }
        loop_count++;
    } while (delta > 0 && loop_count < 100);

    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return cluster_centres;
}

