void allocateMemory(int npoints, int nfeatures, int nclusters, float **features)
{
    num_blocks = npoints / num_threads;
    if (npoints % num_threads > 0)
        num_blocks++;

    num_blocks_perdim = (unsigned int)sqrt((double) num_blocks);
    while (num_blocks > num_blocks_perdim * num_blocks_perdim)
        num_blocks_perdim++;

    num_blocks = num_blocks_perdim * num_blocks_perdim;

    membership_new = (int*) malloc(npoints * sizeof(int));
    for(int i=0; i<npoints; i++) {
        membership_new[i] = -1;
    }

    block_new_centers = (float *) malloc(nclusters*nfeatures*sizeof(float));

    feature_flipped_d = (float *) malloc(npoints*nfeatures*sizeof(float));
    memcpy(feature_flipped_d, features[0], npoints*nfeatures*sizeof(float));

    feature_d = (float *) malloc(npoints*nfeatures*sizeof(float));

    int total_points = npoints;
    int total_features = nfeatures;

    #pragma omp parallel for collapse(2) schedule(static)
    for (int point_id = 0; point_id < total_points; point_id++) {
        for (int i = 0; i < total_features; i++) {
            feature_d[point_id + total_points*i] = feature_flipped_d[point_id*total_features + i];
        }
    }

    membership_d = (int*) malloc(npoints*sizeof(int));
    clusters_d = (float*) malloc(nclusters*nfeatures*sizeof(float));

    block_clusters_d = (float *) malloc(num_blocks_perdim * num_blocks_perdim * nclusters * nfeatures * sizeof(float));
    block_deltas_d = (int *) malloc(num_blocks_perdim * num_blocks_perdim * sizeof(int));

    c_clusters_host = (float*) malloc(nclusters*nfeatures*sizeof(float));
    nclusters_global = nclusters;
    nfeatures_global = nfeatures;
    npoints_global = npoints;
}

void deallocateMemory()
{
    free(membership_new);
    free(block_new_centers);
    free(feature_d);
    free(feature_flipped_d);
    free(membership_d);
    free(clusters_d);
    free(block_clusters_d);
    free(block_deltas_d);
    free(c_clusters_host);
}

