int kmeansCuda(float  **feature,
           int      nfeatures,
           int      npoints,
           int      nclusters,
           int     *membership,
           float  **clusters,
           int     *new_centers_len,
           float  **new_centers
           )
{
    int delta = 0;
    int i, j;

    memcpy(membership_d, membership_new, npoints*sizeof(int));
    memcpy(clusters_d, clusters[0], nclusters*nfeatures*sizeof(float));
    memcpy(c_clusters_host, clusters[0], nclusters*nfeatures*sizeof(float));

    nclusters_global = nclusters;
    nfeatures_global = nfeatures;
    npoints_global = npoints;

    int total_blocks = num_blocks_perdim * num_blocks_perdim;

    #pragma omp parallel
    {
        #pragma omp for schedule(static)
        for (int block_idx = 0; block_idx < total_blocks; block_idx++) {
            block_deltas_d[block_idx] = 0;
            for (int k = 0; k < nclusters * nfeatures; k++) {
                block_clusters_d[block_idx * nclusters * nfeatures + k] = 0.0f;
            }
        }

        #pragma omp for schedule(static)
        for (int point_id = 0; point_id < npoints; point_id++) {
            int block_id = point_id / THREADS_PER_BLOCK;
            int local_idx = point_id % THREADS_PER_BLOCK;

            int index = -1;
            float min_dist = FLT_MAX;

            if (point_id < npoints) {
                for (int i = 0; i < nclusters; i++) {
                    float ans = 0.0;
                    for (int j = 0; j < nfeatures; j++) {
                        int addr = point_id + j * npoints;
                        float val_feat = feature_d[addr];
                        float val_cluster = c_clusters_host[i * nfeatures + j];
                        float diff = val_feat - val_cluster;
                        ans += diff * diff;
                    }
                    if (ans < min_dist) {
                        min_dist = ans;
                        index = i;
                    }
                }
            }

            int local_delta = 0;
            if (point_id < npoints) {
                if (membership_d[point_id] != index) {
                    local_delta = 1;
                }
                membership_d[point_id] = index;
            }

            block_deltas_d[block_id] += local_delta;

            if (point_id < npoints && local_idx < nfeatures * nclusters) {
                int center_id = local_idx / nfeatures;
                int dim_id = local_idx % nfeatures;

                float accumulator = 0.0f;

                for (int t = 0; t < THREADS_PER_BLOCK; t++) {
                    int check_point = (point_id - local_idx) + t;
                    if (check_point < npoints) {
                        int check_cluster = membership_d[check_point];
                        if (check_cluster == center_id) {
                            int addr = check_point + dim_id * npoints;
                            accumulator += feature_d[addr];
                        }
                    }
                }

                block_clusters_d[block_id * nclusters * nfeatures + local_idx] += accumulator;
            }
        }
    }

    memcpy(membership_new, membership_d, npoints*sizeof(int));

    delta = 0;
    for (i = 0; i < npoints; i++) {
        int cluster_id = membership_new[i];
        new_centers_len[cluster_id]++;
        if (membership[i] != membership_new[i]) {
            delta++;
            membership[i] = membership_new[i];
        }
    }

    for (int j = 0; j < nclusters; j++) {
        for (int k = 0; k < nfeatures; k++) {
            block_new_centers[j*nfeatures + k] = 0.0f;
        }
    }

    for (i = 0; i < total_blocks; i++) {
        for (int j = 0; j < nclusters; j++) {
            for (int k = 0; k < nfeatures; k++) {
                block_new_centers[j*nfeatures + k] += block_clusters_d[i * nclusters*nfeatures + j * nfeatures + k];
            }
        }
    }

    for (int j = 0; j < nclusters; j++) {
        for (int k = 0; k < nfeatures; k++) {
            new_centers[j][k] = block_new_centers[j*nfeatures + k];
        }
    }

    return delta;
}
